def expand_ranges(s):
    if not s or not s.strip():
        return []
    result = []
    for part in s.split(','):
        part = part.strip()
        if '-' in part:
            start, end = part.split('-', 1)
            result.extend(range(int(start), int(end) + 1))
        else:
            result.append(int(part))
    return result
